const webhookData = $('Webhook Trigger').first().json;
const b = webhookData.body ?? webhookData;
const run_id = b.run_id || b.runId || b.runID;
const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!run_id) {
  return [{ json: { ok: false, run_id: null, error: { code: 'MISSING_FIELDS', message: 'run_id is required' } } }];
}

if (b.workflow_key !== 'event_attendee_enrich') {
  return [{ json: { ok: false, run_id, error: { code: 'WRONG_WORKFLOW', message: 'workflow_key must be event_attendee_enrich, got: ' + b.workflow_key } } }];
}

if (!b.event_id || typeof b.event_id !== 'string' || !UUID_RE.test(b.event_id)) {
  return [{ json: { ok: false, run_id, error: { code: 'INVALID_EVENT_ID', message: 'event_id must be a valid UUID' } } }];
}

const result = {
  ok: true,
  run_id,
  workflow_key: 'event_attendee_enrich',
  event_id: b.event_id,
  triggered_by: b.triggered_by || null
};

if (b.attendee_ids !== undefined && b.attendee_ids !== null) {
  if (!Array.isArray(b.attendee_ids)) {
    return [{ json: { ok: false, run_id, error: { code: 'INVALID_ATTENDEE_IDS', message: 'attendee_ids must be an array of UUIDs' } } }];
  }
  for (const id of b.attendee_ids) {
    if (typeof id !== 'string' || !UUID_RE.test(id)) {
      return [{ json: { ok: false, run_id, error: { code: 'INVALID_ATTENDEE_ID', message: 'Each attendee_id must be a valid UUID' } } }];
    }
  }
  const capped = b.attendee_ids.slice(0, 50);
  if (capped.length > 0) result.attendee_ids = capped;
}

return [{ json: result }];

const input = $('Normalize Input').first().json;
const fetchResult = $('Fetch Attendees').first().json;

// Detect fetch-level errors (HTTP failures caught by continueOnFail)
const fetchError = fetchResult?.error || null;

// Defensively extract attendee array from various response shapes
let attendees = [];
if (Array.isArray(fetchResult)) {
  attendees = fetchResult;
} else if (fetchResult && Array.isArray(fetchResult.data)) {
  attendees = fetchResult.data;
} else if (fetchResult && Array.isArray(fetchResult.attendees)) {
  attendees = fetchResult.attendees;
} else if (fetchResult && !fetchError) {
  // Single-object response — only wrap if it looks like an attendee
  if (fetchResult.id || fetchResult.attendee_id) {
    attendees = [fetchResult];
  }
}

// Score each attendee for completeness
const enriched_attendees = attendees.map(a => {
  const fields = ['name', 'email', 'title', 'organization', 'phone'];
  const filled = fields.filter(f => a[f] && String(a[f]).trim().length > 0).length;
  const completeness = Math.round((filled / fields.length) * 100);
  return {
    id: a.id || a.attendee_id || null,
    contact_id: a.contact_id || null,
    name: a.name || null,
    email: a.email || null,
    title: a.title || null,
    organization: a.organization || null,
    phone: a.phone || null,
    completeness_score: completeness,
    needs_enrichment: completeness < 60,
    enrichment_source: 'deterministic_v1'
  };
});

return [{ json: {
  run_id: input.run_id,
  event_id: input.event_id,
  enriched_attendees,
  attendee_count: enriched_attendees.length,
  fetch_error: fetchError,
  fetch_returned_empty: attendees.length === 0 && !fetchError
} }];

const input = $('Normalize Input').first().json;
let error = null;
let failed_node = null;

// Check Fetch Attendees for hard failures
try {
  const fetchNode = $('Fetch Attendees').first();
  if (fetchNode.json?.error && typeof fetchNode.json.error === 'string' && fetchNode.json.error.length > 0) {
    // Only treat as error if it's a real HTTP/network failure, not "no data"
    const errStr = String(fetchNode.json.error);
    if (!errStr.includes('404') && !errStr.includes('No attendees')) {
      error = 'Fetch attendees failed: ' + errStr.slice(0, 500);
      failed_node = 'Fetch Attendees';
    }
  }
} catch (e) {
  error = 'Fetch Attendees node did not execute: ' + String(e.message).slice(0, 200);
  failed_node = 'Fetch Attendees';
}

// Check Enrich Attendees for hard failures
if (!error) {
  try {
    const enrichNode = $('Enrich Attendees').first();
    if (enrichNode.json?.error) {
      error = 'Enrich failed: ' + String(enrichNode.json.error).slice(0, 500);
      failed_node = 'Enrich Attendees';
    }
  } catch (e) {
    error = 'Enrich Attendees node did not execute: ' + String(e.message).slice(0, 200);
    failed_node = 'Enrich Attendees';
  }
}

// Build result — "no data" is a valid completed state, not an error
let result = null;
if (!error) {
  try {
    const enrichData = $('Enrich Attendees').first().json;
    result = {
      enriched_attendees: enrichData.enriched_attendees || [],
      attendee_count: enrichData.attendee_count || 0,
      event_id: enrichData.event_id,
      fetch_returned_empty: enrichData.fetch_returned_empty || false
    };
    // fetch_error is informational but NOT a workflow failure if we got empty results
    // Only mark as error if fetch_error exists AND we didn't get any attendees at all
    // AND the error is not a simple "not found" type
    if (enrichData.fetch_error && !enrichData.fetch_returned_empty) {
      error = 'Fetch returned error: ' + String(enrichData.fetch_error).slice(0, 500);
      failed_node = 'Fetch Attendees';
    }
  } catch (e) {
    error = 'Failed to build result envelope: ' + String(e.message).slice(0, 200);
    failed_node = 'Result Envelope';
  }
}

// CRITICAL: status is 'processed' for both "got results" and "no results" cases
// Only 'error' for genuine infrastructure/network failures
return [{ json: {
  run_id: input.run_id,
  workflow_key: 'event_attendee_enrich',
  status: error ? 'error' : 'processed',
  payload: { result, error, failed_node }
} }];
